#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int A[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &A[i][j]);
            }
        }
        int max_trace = 0;
        for (int size = 1; size <= N; size++) {
            for (int i = 0; i <= N - size; i++) {
                for (int j = 0; j <= N - size; j++) {
                    int trace = 0;
                    for (int k = 0; k < size; k++) {
                        trace += A[i + k][j + k];
                    }
                    max_trace = (max_trace > trace) ? max_trace : trace;
                }
            }
        }
        printf("%d\n", max_trace);
    }
    return 0;
}

