import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] A = new int[N][N];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    A[i][j] = sc.nextInt();
                }
            }
            int max_trace = 0;
            for (int size = 1; size <= N; size++) {
                for (int i = 0; i <= N - size; i++) {
                    for (int j = 0; j <= N - size; j++) {
                        int trace = 0;
                        for (int k = 0; k < size; k++) {
                            trace += A[i + k][j + k];
                        }
                        max_trace = Math.max(max_trace, trace);
                    }
                }
            }
            System.out.println(max_trace);
        }
    }
}

